const API_URL = 'https://api.example.com/v2';

function fetchData() {
  return fetch(API_URL)
    .then(response => response.json())
    .catch(error => logger.error('Failed to fetch data', error));
}

function formatDate(date, locale = 'en-US') {
  return new Date(date).toLocaleDateString(locale, {
    year: 'numeric',
    month: 'long',
    day: 'numeric'
  });
}

const logger = {
  info: (message, data = null) => {
    const log = { level: 'INFO', message, timestamp: new Date().toISOString() };
    if (data) log.data = data;
    console.log(JSON.stringify(log));
  },
  warn: (message, data = null) => {
    const log = { level: 'WARN', message, timestamp: new Date().toISOString() };
    if (data) log.data = data;
    console.warn(JSON.stringify(log));
  },
  error: (message, error = null) => {
    const log = { level: 'ERROR', message, timestamp: new Date().toISOString() };
    if (error) log.error = error.message;
    console.error(JSON.stringify(log));
  },
  debug: (message, data = null) => {
    if (process.env.NODE_ENV === 'development') {
      const log = { level: 'DEBUG', message, timestamp: new Date().toISOString() };
      if (data) log.data = data;
      console.log(JSON.stringify(log));
    }
  }
};
